  - id: ensure_artwork_download_stagger
    mode: single
    then: 
      - if: 
          condition: 
            lambda: !lambda |-
              return id(artwork_download_stagger_ms) < 0;
          then: 
            - lambda: !lambda |-
                const uint32_t retry_window_ms = 1500;
                uint32_t retry_stagger_ms = 0;
                uint8_t mac[6] = {0, 0, 0, 0, 0, 0};
                esphome::get_mac_address_raw(mac);
                uint32_t hash = 2166136261UL;
                for (uint8_t byte : mac) {
                  hash ^= byte;
                  hash *= 16777619UL;
                }
                hash ^= 0x9e3779b9UL;
                hash *= 16777619UL;
                if (retry_window_ms > 0) {
                  retry_stagger_ms = hash % retry_window_ms;
                }
                id(artwork_download_stagger_ms) = 0;
                id(artwork_retry_stagger_ms) = static_cast<int>(retry_stagger_ms);
                ESP_LOGD("artwork", "Artwork stagger: download=%u ms retry=%u ms",
                         0U, static_cast<unsigned>(retry_stagger_ms));
    parameters: {}
  - id: apply_downloaded_artwork
    mode: queued
    then: 
      - lvgl.widget.hide: 
          - id: artwork_error_label
      - lambda: !lambda |-
          id(artwork_retry_pending) = false;
          id(artwork_retry_attempts) = 0;
      - lambda: !lambda |-
          auto *img = id(is_tv_mode) ? id(tv_art_background) : id(album_art_background);
          int iw = img->get_width();
          int ih = img->get_height();
          ESP_LOGI("artwork", "Apply start: mode=%s image=%dx%d content=%dx%d offset=%d,%d",
                   id(is_tv_mode) ? "tv" : "music", iw, ih, img->get_content_width(), img->get_content_height(),
                   img->get_content_offset_x(), img->get_content_offset_y());
          auto *w = id(album_art_background_widget);
          constexpr int display_size = 800;
          lv_obj_set_size(w, display_size, display_size);
          lv_obj_set_pos(w, 0, 0);
          lv_img_set_offset_x(w, 0);
          lv_img_set_offset_y(w, 0);
          int dim = (iw < ih) ? iw : ih;
          if (!id(is_tv_mode) && false && dim > 0 && dim < display_size) {
            int zoom = (256 * display_size + dim - 1) / dim;
            lv_img_set_zoom(w, zoom);
          } else {
            lv_img_set_zoom(w, 256);
          }
          lv_obj_align(id(media_progress_bar), LV_ALIGN_BOTTOM_MID, 0, 0);
          ESP_LOGI("artwork", "LVGL image widget: size=%dx%d zoom=%d offsets=%d,%d progress_y=%d",
                   display_size, display_size, lv_img_get_zoom(w), lv_img_get_offset_x(w), lv_img_get_offset_y(w),
                   lv_obj_get_y(id(media_progress_bar)));
      - if: 
          condition: 
            lambda: !lambda |-
              return id(is_tv_mode);
          then: 
            - lvgl.image.update: 
                id: 
                  - id: album_art_background_widget
                src: tv_art_background
          else: 
            - lvgl.image.update: 
                id: 
                  - id: album_art_background_widget
                src: album_art_background
      - lvgl.widget.show: 
          - id: album_art_background_widget
      - lvgl.widget.update: 
          id: 
            - id: album_art_background_widget
          opa: 1.0
      - script.execute: 
          id: extract_accent_color
      - script.wait: 
          id: extract_accent_color
      - script.execute: 
          id: apply_warm_tones
      - lambda: !lambda |-
          ESP_LOGD("artwork", "Apply finished");
    parameters: {}
    max_runs: 5
  - id: handle_artwork_error
    mode: restart
    then: 
      - lambda: !lambda |-
          const std::string &url = id(is_tv_mode) ? id(last_tv_artwork_url) : id(last_artwork_url);
          ESP_LOGW("artwork", "Artwork download failed: %s", url.c_str());
      - if: 
          condition: 
            lambda: !lambda |-
              const std::string &url = id(is_tv_mode) ? id(last_tv_artwork_url) : id(last_artwork_url);
              return !url.empty() && id(artwork_retry_attempts) < 5;
          then: 
            - lambda: !lambda |-
                id(artwork_retry_pending) = true;
                id(artwork_retry_attempts) += 1;
            - script.execute: 
                id: ensure_artwork_download_stagger
            - script.wait: 
                id: ensure_artwork_download_stagger
            - delay: !lambda |-
                const int attempt = id(artwork_retry_attempts);
                uint32_t backoff_ms = 500;
                if (attempt == 2) backoff_ms = 1500;
                else if (attempt == 3) backoff_ms = 3000;
                else if (attempt == 4) backoff_ms = 6000;
                else if (attempt >= 5) backoff_ms = 10000;
                uint32_t device_spread_ms = static_cast<uint32_t>(id(artwork_retry_stagger_ms));
                return static_cast<uint32_t>(backoff_ms + device_spread_ms);
            - lambda: !lambda |-
                auto *img = id(is_tv_mode) ? id(tv_art_background) : id(album_art_background);
                const std::string &url = id(is_tv_mode) ? id(last_tv_artwork_url) : id(last_artwork_url);
                if (!url.empty()) {
                  ESP_LOGI("artwork", "Retrying artwork download attempt %d/5: %s",
                           id(artwork_retry_attempts), url.c_str());
                  img->set_url(url);
                  img->update();
                }
          else: 
            - lambda: !lambda |-
                id(artwork_retry_pending) = false;
                ESP_LOGW("artwork", "Artwork retries exhausted; keeping current artwork visible");
    parameters: {}
  - id: refresh_idle_screen_timer
    mode: restart
    then: 
      - if: 
          condition: 
            lambda: !lambda |-
              std::string state = "";
              if (id(is_tv_mode)) {
                if (id(tv_media_player_state_sensor).has_state()) state = id(tv_media_player_state_sensor).state;
              } else if (id(media_player_state_sensor).has_state()) {
                state = id(media_player_state_sensor).state;
              }
              if (state.empty() || state == "playing") return false;
              if (state == "paused" && !id(backlight_dim_when_paused).state) return false;
              return true;
          then: 
            - script.stop: 
                id: backlight_wake_timeout
            - script.execute: 
                id: backlight_wake_timeout
    parameters: {}
  - id: screen_schedule_check
    mode: restart
    then: 
      - lambda: !lambda |-
          if (!id(schedule_enabled).state) {
            id(screen_schedule_asleep) = false;
            id(screen_schedule_manual_wake_ms) = 0;
            return;
          }

          id(ha_time).set_timezone(id(tz_posix));
          setenv("TZ", id(tz_posix).c_str(), 1);
          tzset();
          auto now = id(ha_time).now();
          if (!now.is_valid()) return;

          int on_hour = (int) id(schedule_on_hour).state;
          int off_hour = (int) id(schedule_off_hour).state;
          if (on_hour < 0) on_hour = 0;
          if (on_hour > 23) on_hour = 23;
          if (off_hour < 0) off_hour = 0;
          if (off_hour > 23) off_hour = 23;

          bool in_window = true;
          if (on_hour < off_hour) {
            in_window = now.hour >= on_hour && now.hour < off_hour;
          } else if (on_hour > off_hour) {
            in_window = now.hour >= on_hour || now.hour < off_hour;
          }

          if (in_window) {
            id(screen_schedule_manual_wake_ms) = 0;
            if (id(screen_schedule_asleep)) {
              id(screen_schedule_asleep) = false;
              id(backlight_wake_timeout).execute();
            }
            return;
          }

          if (id(screen_schedule_manual_wake_ms) != 0) {
            uint32_t elapsed = (uint32_t) (millis() - id(screen_schedule_manual_wake_ms));
            float timeout_s = id(schedule_wake_timeout).state;
            if (!(timeout_s > 0)) timeout_s = 60;
            if (timeout_s < 10) timeout_s = 10;
            if (timeout_s > 3600) timeout_s = 3600;
            uint32_t timeout_ms = (uint32_t) (timeout_s * 1000.0f);
            if (elapsed < timeout_ms) return;
            id(screen_schedule_manual_wake_ms) = 0;
          }

          if (!id(screen_schedule_asleep)) {
            id(screen_schedule_asleep) = true;
            id(hide_clock_view).execute();
          }
          id(turn_off_display).execute();
    parameters: {}
