          if (timeout_s > 3600) timeout_s = 3600;
          return (uint32_t) (timeout_s * 1000.0f);
      - lambda: !lambda |-
          if (!id(schedule_enabled).state || id(screen_schedule_manual_wake_ms) == 0) return;

          id(ha_time).set_timezone(id(tz_posix));
