                  - light.turn_on: 
                      id: backlight
                      brightness: !lambda |-
                        bool is_day = id(day_night_sensor_entity).state.empty()
                            ? (!id(sun_state_sensor).has_state() || id(sun_state_sensor).state == "above_horizon")
                            : id(custom_day_night_is_day);
                        float pct = is_day ? id(clock_brightness).state : id(evening_clock_brightness).state;
                        if (!(pct > 0.0f)) pct = 35.0f;
                        if (pct < 1.0f) pct = 1.0f;
                        if (pct > 100.0f) pct = 100.0f;
                        return 0.02f + (pct / 100.0f) * (1.0f - 0.02f);
