          id(ha_time).set_timezone(id(tz_posix));
          setenv("TZ", id(tz_posix).c_str(), 1);
          tzset();
          auto time = id(ha_time).now();
          int minute = 0;
          if (time.is_valid()) {
            int hour = time.hour;
            if (id(clock_time_format).current_option() == "12 Hour") {
              hour = hour % 12;
              if (hour == 0) hour = 12;
            }
            char buf[7];
            snprintf(buf, sizeof(buf), "%d:%02d", hour, time.minute);
            lv_label_set_text(id(clock_label), buf);
            minute = time.minute;
          }
          lv_obj_update_layout(id(clock_screensaver));
          lv_obj_update_layout(id(clock_label));
          lv_coord_t w = lv_obj_get_width(id(clock_label));
          lv_coord_t h = lv_obj_get_height(id(clock_label));
          int cx = lv_obj_get_width(id(clock_screensaver)) / 2;
          int cy = lv_obj_get_height(id(clock_screensaver)) / 2;
          int ox = (minute * 7) % 25 - 12;
          int oy = (minute * 13) % 17 - 8;
          lv_obj_set_pos(id(clock_label), cx + ox - w/2, cy + oy - h/2);
          lv_obj_invalidate(id(clock_screensaver));
          lv_obj_invalidate(id(clock_label));
