  - id: subscribe_day_night_sensor
    mode: restart
    then: 
      - lambda: !lambda |-
          if (esphome::api::global_api_server == nullptr) return;
          std::string entity = id(day_night_sensor_entity).state;
          if (entity.empty()) {
            id(subscribed_day_night_sensor_entity) = "";
            id(day_night_subscription_gen) += 1;
            id(apply_day_night_backlight).execute();
            return;
          }
          if (entity.substr(0, 14) != "binary_sensor." && entity.substr(0, 14) != "input_boolean.") {
            ESP_LOGW("backlight", "Invalid day/night entity '%s' — must start with 'binary_sensor.' or 'input_boolean.'", entity.c_str());
            id(subscribed_day_night_sensor_entity) = "";
            id(day_night_subscription_gen) += 1;
            return;
