          if (entity == id(subscribed_day_night_sensor_entity)) {
            ESP_LOGD("backlight", "Already subscribed to day/night sensor '%s'", entity.c_str());
            return;
          }
          id(day_night_subscription_gen) += 1;
          id(subscribed_day_night_sensor_entity) = entity;
          int gen = id(day_night_subscription_gen);
          int *gen_ptr = &id(day_night_subscription_gen);
          auto *api = esphome::api::global_api_server;
          api->subscribe_home_assistant_state(entity, esphome::optional<std::string>(""),
              std::function<void(esphome::StringRef)>([gen, gen_ptr](esphome::StringRef state) {
                if (gen != *gen_ptr) return;
                id(custom_day_night_is_day) = (state == "on");
                id(apply_day_night_backlight).execute();
              }));
          ESP_LOGI("backlight", "Subscribed to day/night sensor '%s'", entity.c_str());
    parameters: {}
