  - id: update_setup_ip_label
    mode: restart
    then: 
      - lambda: !lambda |-
          auto ips = wifi::global_wifi_component->get_ip_addresses();
          if (!ips.empty()) {
            char ip_buf[esphome::network::IP_ADDRESS_BUFFER_SIZE];
            ips[0].str_to(ip_buf);
