            lv_label_set_text(id(setup_ip_label), url.c_str());
          }
    parameters: {}
  - id: parse_speakers
    mode: restart
    then: 
      - lambda: !lambda |-
          std::string raw = id(speakers_sensor).state;

          if (raw.empty() || raw == "None" || raw == "unknown") {
            id(speaker_count) = 0;
            ESP_LOGW("speaker_group", "No speakers found — showing fallback");
            id(show_fallback_speaker).execute();
            return;
          }

          // Split on '|' into ids / names / volumes / manufacturers sections
          size_t p1 = raw.find('|');
          size_t p2 = (p1 != std::string::npos) ? raw.find('|', p1 + 1) : std::string::npos;
          size_t p3 = (p2 != std::string::npos) ? raw.find('|', p2 + 1) : std::string::npos;
          std::string ids_raw   = (p1 != std::string::npos) ? raw.substr(0, p1) : raw;
          std::string names_raw = (p1 != std::string::npos && p2 != std::string::npos)
              ? raw.substr(p1 + 1, p2 - p1 - 1) : "";
          std::string vols_raw  = (p2 != std::string::npos && p3 != std::string::npos)
              ? raw.substr(p2 + 1, p3 - p2 - 1)
              : (p2 != std::string::npos) ? raw.substr(p2 + 1) : "";
          std::string mfrs_raw  = (p3 != std::string::npos) ? raw.substr(p3 + 1) : "";

          // Helper: split a comma-separated string into a vector, trimming whitespace
          auto split_csv = [](const std::string &s, size_t max) {
            std::vector<std::string> out;
            size_t start = 0, end;
            while ((end = s.find(',', start)) != std::string::npos && out.size() < max) {
              std::string t = s.substr(start, end - start);
              while (!t.empty() && t.front() == ' ') t.erase(0, 1);
              while (!t.empty() && t.back() == ' ') t.pop_back();
              out.push_back(t);
              start = end + 1;
            }
            if (start < s.size() && out.size() < max) {
              std::string t = s.substr(start);
              while (!t.empty() && t.front() == ' ') t.erase(0, 1);
              while (!t.empty() && t.back() == ' ') t.pop_back();
              out.push_back(t);
            }
            return out;
          };

          std::vector<std::string> ids   = split_csv(ids_raw, 16);
          std::vector<std::string> names = split_csv(names_raw, 16);
          std::vector<std::string> vtoks = split_csv(vols_raw, 16);
          std::vector<std::string> mfrs  = split_csv(mfrs_raw, 16);

          // Restore full entity IDs (prefix stripped in HA template for brevity)
          for (auto &eid : ids) {
            if (!eid.empty()) eid = "media_player." + eid;
          }

          // Convert volume strings to floats
          std::vector<float> vols;
          for (auto &t : vtoks) {
            auto v = esphome::parse_number<float>(t);
            vols.push_back(v.has_value() ? v.value() : 0.0f);
          }

          std::string old_entity_ids[16];
          float old_volumes[16];
          int old_pending_from_pct[16];
          int old_pending_direction[16];
          uint32_t old_pending_until[16];
          for (int i = 0; i < 16; i++) {
            old_entity_ids[i] = id(speaker_entity_ids)[i];
            old_volumes[i] = id(speaker_volumes)[i];
            old_pending_from_pct[i] = id(speaker_volume_pending_from_pct)[i];
            old_pending_direction[i] = id(speaker_volume_pending_direction)[i];
            old_pending_until[i] = id(speaker_volume_pending_until)[i];
          }

          // Reset globals
          id(speaker_count) = 0;
          for (int i = 0; i < 16; i++) {
            id(speaker_entity_ids)[i] = "";
            id(speaker_names)[i] = "";
            id(speaker_grouped)[i] = false;
            id(speaker_volumes)[i] = 0.0f;
            id(speaker_volume_pending_from_pct)[i] = -1;
            id(speaker_volume_pending_direction)[i] = 0;
            id(speaker_volume_pending_until)[i] = 0;
          }

          if (ids.empty()) {
            ESP_LOGW("speaker_group", "No speakers parsed — showing fallback");
            id(show_fallback_speaker).execute();
            return;
          }

          // If the selected player isn't in the speaker list, show fallback
          std::string selected = id(media_player_entity).state;
          bool found_selected = false;
          for (size_t i = 0; i < ids.size(); i++) {
            if (ids[i] == selected) { found_selected = true; break; }
          }
          if (!found_selected) {
            ESP_LOGD("speaker_group", "Selected player '%s' not in speaker list — showing fallback", selected.c_str());
            id(show_fallback_speaker).execute();
            return;
          }

          // Determine selected entity's manufacturer for filtering
          std::string selected_mfr;
          if (!mfrs.empty()) {
            for (size_t i = 0; i < ids.size(); i++) {
              if (ids[i] == selected && i < mfrs.size()) {
                selected_mfr = mfrs[i];
                break;
              }
            }
          }

          // Fill speakers, skipping those with a different manufacturer
          int count = 0;
          for (size_t i = 0; i < ids.size() && count < 16; i++) {
            if (!selected_mfr.empty() && i < mfrs.size()
                && !mfrs[i].empty() && mfrs[i] != selected_mfr) {
              continue;
            }
            id(speaker_entity_ids)[count] = ids[i];
            id(speaker_names)[count] = (i < names.size()) ? names[i] : ids[i];

            float parsed_volume = (i < vols.size()) ? vols[i] : 0.0f;
            if (parsed_volume < 0.0f) parsed_volume = 0.0f;
            if (parsed_volume > 1.0f) parsed_volume = 1.0f;
            int parsed_pct = (int)(parsed_volume * 100.0f + 0.5f);

            int old_index = -1;
            for (int j = 0; j < 16; j++) {
              if (old_entity_ids[j] == ids[i]) {
                old_index = j;
                break;
              }
            }

            id(speaker_volumes)[count] = parsed_volume;
            if (old_index >= 0 && old_pending_until[old_index] != 0) {
              uint32_t now = millis();
              bool pending_active = (int32_t)(old_pending_until[old_index] - now) > 0;
              int pending_from = old_pending_from_pct[old_index];
              int pending_direction = old_pending_direction[old_index];
              bool stale_echo = pending_active
                  && ((pending_direction < 0 && parsed_pct >= pending_from)
                      || (pending_direction > 0 && parsed_pct <= pending_from));

              if (stale_echo) {
                id(speaker_volumes)[count] = old_volumes[old_index];
                id(speaker_volume_pending_from_pct)[count] = pending_from;
                id(speaker_volume_pending_direction)[count] = pending_direction;
                id(speaker_volume_pending_until)[count] = old_pending_until[old_index];
                ESP_LOGD("speaker_group", "Ignoring stale volume echo for %s: %d%%",
                         ids[i].c_str(), parsed_pct);
              }
            }
            count++;
          }
          int selected_index = -1;
          for (int i = 0; i < count; i++) {
            if (id(speaker_entity_ids)[i] == selected) {
              selected_index = i;
              break;
            }
          }
