          std::vector<std::string> members;
          size_t start = 0, end;
          while ((end = raw.find(',', start)) != std::string::npos) {
            std::string token = raw.substr(start, end - start);
            // Strip whitespace and quotes from each token
            while (!token.empty() && (token.front() == ' ' || token.front() == '\'' || token.front() == '"'))
              token.erase(0, 1);
            while (!token.empty() && (token.back() == ' ' || token.back() == '\'' || token.back() == '"'))
              token.pop_back();
            if (!token.empty()) members.push_back(token);
            start = end + 1;
          }
          if (start < raw.size()) {
            std::string token = raw.substr(start);
            while (!token.empty() && (token.front() == ' ' || token.front() == '\'' || token.front() == '"'))
              token.erase(0, 1);
