            id(last_tv_media_position) = pos;
            if (t.is_valid()) id(last_tv_position_timestamp) = t.timestamp;
          } else {
            id(last_media_position) = pos;
            if (t.is_valid()) id(last_position_timestamp) = t.timestamp;
          }

          const int progress_range = 100;
          int value = 0;
          if (dur > 0.0f) {
            value = (int)((pos / dur) * (float)progress_range + 0.5f);
          }
          if (value < 0) value = 0;
          if (value > progress_range) value = progress_range;

          if (lv_obj_has_flag(id(media_progress_bar), LV_OBJ_FLAG_HIDDEN)) {
            lv_obj_clear_flag(id(media_progress_bar), LV_OBJ_FLAG_HIDDEN);
          }

          if (tv_mode) {
            if (value == id(last_tv_progress_percent)) return;
            id(last_tv_progress_percent) = value;
          } else {
            if (value == id(last_media_progress_percent)) return;
            id(last_media_progress_percent) = value;
          }

          const int expected_bar_y = 800 - 4;
          const int actual_bar_y = lv_obj_get_y(id(media_progress_bar));
          if (actual_bar_y != expected_bar_y) {
            ESP_LOGW("display_guard", "Progress bar y changed from %d to %d; re-aligning to bottom",
                     expected_bar_y, actual_bar_y);
            lv_obj_align(id(media_progress_bar), LV_ALIGN_BOTTOM_MID, 0, 0);
          }

          lv_bar_set_range(id(media_progress_bar), 0, progress_range);
          lv_obj_set_style_anim_duration(id(media_progress_bar), 0, LV_PART_MAIN);
          lv_bar_set_value(id(media_progress_bar), value, LV_ANIM_OFF);
