  - id: warm_tones_done
    mode: single
    then: 
      - lambda: !lambda |-
          return;
    parameters: {}
  - id: apply_warm_tones
    mode: queued
    then: 
      - lambda: !lambda |-
          uint32_t apply_start = millis();
          bool retint = id(warm_tone_retint);
          id(warm_tone_retint) = false;

          bool is_day = id(day_night_sensor_entity).state.empty()
              ? (!id(sun_state_sensor).has_state() || id(sun_state_sensor).state == "above_horizon")
              : id(custom_day_night_is_day);
          float w = (is_day ? id(screen_warmth_day).state : id(screen_warmth_night).state) / 100.0f;
          float last_w = retint ? id(warm_tone_last_w) : 0.0f;

          if (retint && fabsf(w - last_w) < 0.01f) return;

          ESP_LOGI("warm", "Warmth: %d%% -> %d%%", (int)(last_w * 100.0f + 0.5f), (int)(w * 100.0f + 0.5f));

          const float red_boost = 0.12f;
          const float green_reduce = 0.14f;
          const float blue_reduce = 0.45f;
          const float contrast_boost = 0.0f;
          const float saturation_boost = 0.0f;

          float r_undo = (last_w > 0.005f) ? 1.0f / (1.0f + last_w * red_boost) : 1.0f;
          float g_undo = (last_w > 0.005f) ? 1.0f / (1.0f - last_w * green_reduce) : 1.0f;
          float b_undo = (last_w > 0.005f) ? 1.0f / (1.0f - last_w * blue_reduce) : 1.0f;
          float r_apply = 1.0f + w * red_boost;
          float g_apply = 1.0f - w * green_reduce;
          float b_apply = 1.0f - w * blue_reduce;

          uint8_t r_lut[32], g_lut[64], b_lut[32];
          for (int i = 0; i < 32; i++) {
            int v = (i << 3) | (i >> 2);
            int nv = (int)(v * r_undo * r_apply);
            r_lut[i] = (uint8_t)((nv > 255 ? 255 : (nv < 0 ? 0 : nv)) >> 3);
          }
          for (int i = 0; i < 64; i++) {
            int v = (i << 2) | (i >> 4);
            int nv = (int)(v * g_undo * g_apply);
            g_lut[i] = (uint8_t)((nv > 255 ? 255 : (nv < 0 ? 0 : nv)) >> 2);
          }
          for (int i = 0; i < 32; i++) {
            int v = (i << 3) | (i >> 2);
            int nv = (int)(v * b_undo * b_apply);
            b_lut[i] = (uint8_t)((nv > 255 ? 255 : (nv < 0 ? 0 : nv)) >> 3);
          }
          const bool apply_contrast = !retint && contrast_boost > 0.001f;
          const bool apply_saturation = !retint && saturation_boost > 0.001f;
          const int contrast_q8 = apply_contrast ? (int)((1.0f + contrast_boost) * 256.0f + 0.5f) : 256;
          const int saturation_q8 = apply_saturation ? (int)((1.0f + saturation_boost) * 256.0f + 0.5f) : 256;

          auto *img = id(is_tv_mode) ? id(tv_art_background) : id(album_art_background);
          if (!img) return;
          #if ESPHOME_VERSION_CODE >= VERSION_CODE(2026, 4, 0)
          auto *dsc = img->get_lv_image_dsc();
          #else
          auto *dsc = img->get_lv_img_dsc();
          #endif
          if (!dsc || !dsc->data) return;
          uint8_t *buf = const_cast<uint8_t*>(dsc->data);
          int total = img->get_width() * img->get_height();
          ESP_LOGD("warm", "Warmth apply start: image=%dx%d pixels=%d retint=%s",
                   img->get_width(), img->get_height(), total, retint ? "yes" : "no");
          for (int i = 0; i < total; i++) {
            if ((i & 0x0FFF) == 0) App.feed_wdt();
            int pos = i * 2;
            uint16_t px = buf[pos] | (buf[pos + 1] << 8);
            int r = ((int)r_lut[(px >> 11) & 0x1F] << 3);
            int g = ((int)g_lut[(px >> 5) & 0x3F] << 2);
            int b = ((int)b_lut[px & 0x1F] << 3);
            if (apply_contrast) {
              r = ((r - 128) * contrast_q8) / 256 + 128;
              g = ((g - 128) * contrast_q8) / 256 + 128;
              b = ((b - 128) * contrast_q8) / 256 + 128;
            }
            if (apply_saturation) {
              int gray = (r * 77 + g * 150 + b * 29) >> 8;
              r = ((r - gray) * saturation_q8) / 256 + gray;
              g = ((g - gray) * saturation_q8) / 256 + gray;
              b = ((b - gray) * saturation_q8) / 256 + gray;
            }
            if (r > 255) r = 255; else if (r < 0) r = 0;
            if (g > 255) g = 255; else if (g < 0) g = 0;
            if (b > 255) b = 255; else if (b < 0) b = 0;
            uint16_t out = ((r >> 3) << 11) | ((g >> 2) << 5) | (b >> 3);
            buf[pos]     = out & 0xFF;
            buf[pos + 1] = (out >> 8) & 0xFF;
          }
          App.feed_wdt();

          lv_obj_invalidate(id(album_art_background_widget));
          id(warm_tone_last_w) = w;
          ESP_LOGD("warm", "Warmth apply finished in %ums", (unsigned) (millis() - apply_start));
      - script.execute: 
          id: warm_tones_done
    parameters: {}
    max_runs: 5
