          const int screen_h = landscape ? 800 : 1280;

          auto resize_fullscreen_overlay = [](lv_obj_t *obj, lv_coord_t width, lv_coord_t height) {
            if (obj == nullptr) {
              return;
            }
            lv_obj_set_pos(obj, 0, 0);
            lv_obj_set_size(obj, width, height);

            lv_obj_t *content = lv_obj_get_child(obj, 0);
            if (content != nullptr) {
              lv_obj_center(content);
            }
