          lv_obj_set_size(id(settings_panel), screen_w, screen_h);
          lv_obj_set_size(id(favorites_panel), screen_w, screen_h);
          lv_obj_set_size(id(clock_screensaver), screen_w, screen_h);

          resize_fullscreen_overlay(id(setup_prompt), screen_w, screen_h);
          resize_fullscreen_overlay(id(actions_prompt), screen_w, screen_h);
          resize_fullscreen_overlay(id(ha_setup_prompt), screen_w, screen_h);
          resize_fullscreen_overlay(id(wifi_setup_prompt), screen_w, screen_h);
          resize_fullscreen_overlay(id(loading_screen), screen_w, screen_h);

          if (!lv_obj_has_flag(id(setup_prompt), LV_OBJ_FLAG_HIDDEN)) {
