  - id: screen_schedule_check
    mode: restart
    then: 
      - lambda: !lambda |-
          if (!id(schedule_enabled).state) {
            id(screen_schedule_asleep) = false;
            id(screen_schedule_manual_wake_ms) = 0;
            return;
          }

          id(ha_time).set_timezone(id(tz_posix));
          setenv("TZ", id(tz_posix).c_str(), 1);
          tzset();
          auto now = id(ha_time).now();
          if (!now.is_valid()) return;

          int on_hour = (int) id(schedule_on_hour).state;
          int off_hour = (int) id(schedule_off_hour).state;
          if (on_hour < 0) on_hour = 0;
          if (on_hour > 23) on_hour = 23;
          if (off_hour < 0) off_hour = 0;
          if (off_hour > 23) off_hour = 23;

          bool in_window = true;
          if (on_hour < off_hour) {
            in_window = now.hour >= on_hour && now.hour < off_hour;
          } else if (on_hour > off_hour) {
            in_window = now.hour >= on_hour || now.hour < off_hour;
          }

          if (in_window) {
            id(screen_schedule_manual_wake_ms) = 0;
            if (id(screen_schedule_asleep)) {
              id(screen_schedule_asleep) = false;
              id(backlight_wake_timeout).execute();
            }
            return;
          }

          if (id(screen_schedule_manual_wake_ms) != 0) {
            uint32_t elapsed = (uint32_t) (millis() - id(screen_schedule_manual_wake_ms));
            float timeout_s = id(schedule_wake_timeout).state;
            if (!(timeout_s > 0)) timeout_s = 60;
            if (timeout_s < 10) timeout_s = 10;
            if (timeout_s > 3600) timeout_s = 3600;
            uint32_t timeout_ms = (uint32_t) (timeout_s * 1000.0f);
            if (elapsed < timeout_ms) return;
            id(screen_schedule_manual_wake_ms) = 0;
          }

          if (!id(screen_schedule_asleep)) {
            id(screen_schedule_asleep) = true;
            id(hide_clock_view).execute();
          }
          id(turn_off_display).execute();
