          }
          id(day_night_subscription_gen) += 1;
          id(subscribed_day_night_sensor_entity) = entity;
          int gen = id(day_night_subscription_gen);
          int *gen_ptr = &id(day_night_subscription_gen);
          auto *api = esphome::api::global_api_server;
          api->subscribe_home_assistant_state(entity, esphome::optional<std::string>(""),
