            ESP_LOGD("speaker_group", "Selected player '%s' not in speaker list — showing fallback", selected.c_str());
            id(show_fallback_speaker).execute();
            return;
          }

          // Determine selected entity's manufacturer for filtering
          std::string selected_mfr;
          if (!mfrs.empty()) {
            for (size_t i = 0; i < ids.size(); i++) {
              if (ids[i] == selected && i < mfrs.size()) {
                selected_mfr = mfrs[i];
                break;
              }
            }
          }

          // Fill speakers, skipping those with a different manufacturer
          int count = 0;
          for (size_t i = 0; i < ids.size() && count < 16; i++) {
            if (!selected_mfr.empty() && i < mfrs.size()
                && !mfrs[i].empty() && mfrs[i] != selected_mfr) {
              continue;
            }
            id(speaker_entity_ids)[count] = ids[i];
            id(speaker_names)[count] = (i < names.size()) ? names[i] : ids[i];

            float parsed_volume = (i < vols.size()) ? vols[i] : 0.0f;
            if (parsed_volume < 0.0f) parsed_volume = 0.0f;
            if (parsed_volume > 1.0f) parsed_volume = 1.0f;
            int parsed_pct = (int)(parsed_volume * 100.0f + 0.5f);

            int old_index = -1;
            for (int j = 0; j < 16; j++) {
              if (old_entity_ids[j] == ids[i]) {
                old_index = j;
                break;
              }
            }

            id(speaker_volumes)[count] = parsed_volume;
            if (old_index >= 0 && old_pending_until[old_index] != 0) {
              uint32_t now = millis();
              bool pending_active = (int32_t)(old_pending_until[old_index] - now) > 0;
              int pending_from = old_pending_from_pct[old_index];
              int pending_direction = old_pending_direction[old_index];
              bool stale_echo = pending_active
                  && ((pending_direction < 0 && parsed_pct >= pending_from)
                      || (pending_direction > 0 && parsed_pct <= pending_from));

              if (stale_echo) {
                id(speaker_volumes)[count] = old_volumes[old_index];
                id(speaker_volume_pending_from_pct)[count] = pending_from;
                id(speaker_volume_pending_direction)[count] = pending_direction;
                id(speaker_volume_pending_until)[count] = old_pending_until[old_index];
                ESP_LOGD("speaker_group", "Ignoring stale volume echo for %s: %d%%",
                         ids[i].c_str(), parsed_pct);
              }
            }
            count++;
          }
          int selected_index = -1;
          for (int i = 0; i < count; i++) {
            if (id(speaker_entity_ids)[i] == selected) {
              selected_index = i;
              break;
            }
          }
          if (selected_index > 0) {
            std::swap(id(speaker_entity_ids)[0], id(speaker_entity_ids)[selected_index]);
            std::swap(id(speaker_names)[0], id(speaker_names)[selected_index]);
            std::swap(id(speaker_volumes)[0], id(speaker_volumes)[selected_index]);
            std::swap(id(speaker_volume_pending_from_pct)[0], id(speaker_volume_pending_from_pct)[selected_index]);
            std::swap(id(speaker_volume_pending_direction)[0], id(speaker_volume_pending_direction)[selected_index]);
            std::swap(id(speaker_volume_pending_until)[0], id(speaker_volume_pending_until)[selected_index]);
          }

          // Slot 0 is the selected player/leader card, so only sort the rest.
          for (int i = 1; i < count - 1; i++) {
            for (int j = i + 1; j < count; j++) {
              if (id(speaker_names)[i] > id(speaker_names)[j]) {
                std::swap(id(speaker_entity_ids)[i], id(speaker_entity_ids)[j]);
                std::swap(id(speaker_names)[i], id(speaker_names)[j]);
                std::swap(id(speaker_volumes)[i], id(speaker_volumes)[j]);
                std::swap(id(speaker_volume_pending_from_pct)[i], id(speaker_volume_pending_from_pct)[j]);
                std::swap(id(speaker_volume_pending_direction)[i], id(speaker_volume_pending_direction)[j]);
                std::swap(id(speaker_volume_pending_until)[i], id(speaker_volume_pending_until)[j]);
              }
            }
          }

          id(speaker_count) = count;
          ESP_LOGI("speaker_group", "Discovered %d speakers", count);

          if (count > 1) {
            if (800 >= 800) {
              lv_label_set_text(id(speakers_title_label), "Speakers");
              lv_obj_clear_flag(id(speakers_title_label), LV_OBJ_FLAG_HIDDEN);
            } else {
              lv_obj_add_flag(id(speakers_title_label), LV_OBJ_FLAG_HIDDEN);
            }
            lv_obj_clear_flag(id(speakers_container), LV_OBJ_FLAG_HIDDEN);
            lv_obj_clear_flag(id(speakers_close_button), LV_OBJ_FLAG_HIDDEN);
            lv_obj_clear_flag(id(group_vol_card), LV_OBJ_FLAG_HIDDEN);
            id(update_group_state).execute();
          } else {
            id(show_fallback_speaker).execute();
          }
