  - id: refresh_progress_bar_from_state
    mode: restart
    then: 
      - lambda: !lambda |-
          if (id(web_settings_active) || !id(show_progress_bar).state || id(is_tv_idle)) {
            return;
          }

          const bool tv_mode = id(is_tv_mode);
          float dur = tv_mode && id(tv_media_duration_sensor).has_state()
              ? id(tv_media_duration_sensor).state
              : (!tv_mode && id(media_duration_sensor).has_state() ? id(media_duration_sensor).state : 0.0f);
          float pos = tv_mode ? id(last_tv_media_position) : id(last_media_position);
          bool playing = tv_mode
              ? (id(tv_media_player_state_sensor).has_state() && id(tv_media_player_state_sensor).state == "playing")
              : (id(media_player_state_sensor).has_state() && id(media_player_state_sensor).state == "playing");

          auto t = id(ha_time).now();
          if (playing && t.is_valid()) {
            if (tv_mode && id(tv_ha_position_epoch) != 0 && id(tv_media_position_sensor).has_state()) {
              pos = id(tv_media_position_sensor).state + (float)(t.timestamp - id(tv_ha_position_epoch));
            } else if (!tv_mode && id(ha_position_epoch) != 0 && id(media_position_sensor).has_state()) {
              pos = id(media_position_sensor).state + (float)(t.timestamp - id(ha_position_epoch));
            }
          }

          if (pos < 0) pos = 0;
          if (dur > 0.0f && pos > dur) pos = dur;

          if (tv_mode) {
            id(last_tv_media_position) = pos;
            if (t.is_valid()) id(last_tv_position_timestamp) = t.timestamp;
          } else {
            id(last_media_position) = pos;
            if (t.is_valid()) id(last_position_timestamp) = t.timestamp;
          }

          const int progress_range = 100;
          int value = 0;
          if (dur > 0.0f) {
            value = (int)((pos / dur) * (float)progress_range + 0.5f);
          }
          if (value < 0) value = 0;
          if (value > progress_range) value = progress_range;

          if (lv_obj_has_flag(id(media_progress_bar), LV_OBJ_FLAG_HIDDEN)) {
            lv_obj_clear_flag(id(media_progress_bar), LV_OBJ_FLAG_HIDDEN);
          }

          if (tv_mode) {
            if (value == id(last_tv_progress_percent)) return;
            id(last_tv_progress_percent) = value;
          } else {
            if (value == id(last_media_progress_percent)) return;
            id(last_media_progress_percent) = value;
          }

          const int expected_bar_y = 800 - 4;
          const int actual_bar_y = lv_obj_get_y(id(media_progress_bar));
          if (actual_bar_y != expected_bar_y) {
            ESP_LOGW("display_guard", "Progress bar y changed from %d to %d; re-aligning to bottom",
                     expected_bar_y, actual_bar_y);
            lv_obj_align(id(media_progress_bar), LV_ALIGN_BOTTOM_MID, 0, 0);
          }

          lv_bar_set_range(id(media_progress_bar), 0, progress_range);
          lv_obj_set_style_anim_duration(id(media_progress_bar), 0, LV_PART_MAIN);
          lv_bar_set_value(id(media_progress_bar), value, LV_ANIM_OFF);
