  - id: load_favorites_from_json
    mode: single
    then: 
      - lambda: !lambda |-
          std::string ha_ip = "";
          if (esphome::api::global_api_server != nullptr) {
            for (auto &client : esphome::api::global_api_server->active_clients()) {
              char buf[esphome::socket::SOCKADDR_STR_LEN];
              const char *peer = client->get_peername_to(std::span<char, esphome::socket::SOCKADDR_STR_LEN>(buf));
              if (peer != nullptr && peer[0] != '\0') {
                ha_ip = std::string(peer);
                auto colon = ha_ip.rfind(':');
                if (colon != std::string::npos) ha_ip = ha_ip.substr(0, colon);
                break;
              }
            }
          }
          if (!ha_ip.empty()) {
            id(ha_base_url) = "http://" + ha_ip + ":8123";
            ESP_LOGI("favorites", "HA discovered at: %s", id(ha_base_url).c_str());
          } else {
            ESP_LOGW("favorites", "No HA API client connected");
          }
      - http_request.get: 
          url: !lambda |-
            return id(ha_base_url) + "/local/favorites.json";
          capture_response: True
          on_response: 
            then: 
              - logger.log: 
                  format: favorites.json response: %d
                  args: 
                    - !lambda |-
                        response->status_code
                  tag: main
                  level: DEBUG
              - lambda: !lambda |-
                  if (response->status_code != 200) {
                    ESP_LOGW("favorites", "Failed to fetch favorites.json: %d", response->status_code);
                    return;
                  }

                  struct Fav { std::string id, name, thumb; bool shuffle = false; };
                  std::vector<Fav> favs;

                  auto find_str = [&](const std::string &src, const std::string &key, size_t from) -> std::pair<std::string, size_t> {
                    size_t k = src.find("\"" + key + "\"", from);
                    if (k == std::string::npos) return {"", std::string::npos};
                    size_t q1 = src.find('"', k + key.size() + 2);
                    if (q1 == std::string::npos) return {"", std::string::npos};
                    q1++;
                    size_t q2 = src.find('"', q1);
                    if (q2 == std::string::npos) return {"", std::string::npos};
                    return {src.substr(q1, q2 - q1), q2};
                  };

                  size_t pos = 0;
                  while (favs.size() < 12) {
                    size_t ob = body.find('{', pos);
                    size_t cb = body.find('}', ob == std::string::npos ? 0 : ob);
                    if (ob == std::string::npos || cb == std::string::npos) break;
                    std::string obj = body.substr(ob, cb - ob + 1);
                    auto [id_v,    p1] = find_str(obj, "id",    0);
                    auto [name_v,  p2] = find_str(obj, "name",  0);
                    auto [thumb_v, p3] = find_str(obj, "thumb", 0);
                    if (!id_v.empty()) {
                      auto [shuffle_v, p4] = find_str(obj, "shuffle", 0);
                      bool shuffle = (shuffle_v == "true");
                      favs.push_back({id_v, name_v, thumb_v, shuffle});
                    }
                    pos = cb + 1;
                  }

                  ESP_LOGI("favorites", "Loaded %d favorites", (int)favs.size());

                  std::string* ids[] = {
                    &id(fav_content_id_1),  &id(fav_content_id_2),  &id(fav_content_id_3),
                    &id(fav_content_id_4),  &id(fav_content_id_5),  &id(fav_content_id_6),
                    &id(fav_content_id_7),  &id(fav_content_id_8),
                  };
                  bool* shuffles[] = {
                    &id(fav_shuffle_1),  &id(fav_shuffle_2),  &id(fav_shuffle_3),
                    &id(fav_shuffle_4),  &id(fav_shuffle_5),  &id(fav_shuffle_6),
                    &id(fav_shuffle_7),  &id(fav_shuffle_8),
                  };
                  lv_obj_t* cards[] = {
                    id(fav_card_1),  id(fav_card_2),  id(fav_card_3),
                    id(fav_card_4),  id(fav_card_5),  id(fav_card_6),
                    id(fav_card_7),  id(fav_card_8),
                  };
                  lv_obj_t* labels[] = {
                    id(fav_label_1),  id(fav_label_2),  id(fav_label_3),
                    id(fav_label_4),  id(fav_label_5),  id(fav_label_6),
                    id(fav_label_7),  id(fav_label_8),
                  };
                  esphome::artwork_image::ArtworkImage* arts[] = {
                    id(fav_art_1),  id(fav_art_2),  id(fav_art_3),
                    id(fav_art_4),  id(fav_art_5),  id(fav_art_6),
                    id(fav_art_7),  id(fav_art_8),
                  };

                  for (int i = 0; i < 8; i++) {
                    if (i < (int)favs.size()) {
                      *ids[i] = favs[i].id;
                      *shuffles[i] = favs[i].shuffle;
                      lv_label_set_text(labels[i], favs[i].name.empty() ? " " : favs[i].name.c_str());
                      if (favs[i].name.empty()) {
                        lv_obj_set_style_bg_opa(labels[i], LV_OPA_TRANSP, 0);
                      } else {
                        lv_obj_set_style_bg_opa(labels[i], LV_OPA_30, 0);
                      }
                      if (!favs[i].thumb.empty()) {
                        std::string thumb_url = favs[i].thumb;
                        if (!thumb_url.empty() && thumb_url[0] == '/') {
                          thumb_url = id(ha_base_url) + thumb_url;
                        }
                        arts[i]->request_update_url(thumb_url);
                      }
                      lv_obj_clear_flag(cards[i], LV_OBJ_FLAG_HIDDEN);
                    } else {
                      *ids[i] = "";
                      lv_obj_add_flag(cards[i], LV_OBJ_FLAG_HIDDEN);
                    }
                  }
          max_response_buffer_size: 1000
          method: GET
