  - id: load_exclude_players
    mode: single
    then: 
      - http_request.get: 
          url: !lambda |-
            return id(ha_base_url) + "/local/exclude_players.json";
          capture_response: True
          on_response: 
            then: 
              - lambda: !lambda |-
                  id(excluded_player_count) = 0;
                  if (response->status_code != 200) {
                    ESP_LOGI("exclude", "No exclude_players.json found (status %d) — no exclusions", response->status_code);
                    return;
                  }
                  size_t pos = 0;
                  int count = 0;
                  while (count < 16) {
                    size_t q1 = body.find('"', pos);
                    if (q1 == std::string::npos) break;
                    q1++;
                    size_t q2 = body.find('"', q1);
                    if (q2 == std::string::npos) break;
                    std::string entity = body.substr(q1, q2 - q1);
                    if (!entity.empty() && entity.substr(0, 13) == "media_player.") {
                      id(excluded_player_ids)[count++] = entity;
                      ESP_LOGI("exclude", "Excluding player: %s", entity.c_str());
                    }
                    pos = q2 + 1;
                  }
                  id(excluded_player_count) = count;
                  ESP_LOGI("exclude", "Loaded %d excluded players", count);
          max_response_buffer_size: 1000
          method: GET
    parameters: {}
  - id: parse_unavailable_speakers
    mode: single
    then: 
      - lambda: !lambda |-
          for (int i = 0; i < 16; i++) id(speaker_unavailable)[i] = false;
          std::string raw = id(speakers_sensor).state;
          if (raw.empty() || raw == "None" || raw == "unknown") return;
          size_t p1 = raw.find('|');
          if (p1 == std::string::npos) return;
          size_t p2 = raw.find('|', p1 + 1);
          if (p2 == std::string::npos) return;
          size_t p3 = raw.find('|', p2 + 1);
          std::string vol_str = raw.substr(p2 + 1, p3 == std::string::npos ? std::string::npos : p3 - p2 - 1);
          int idx = 0;
          size_t pos = 0;
          while (idx < 16) {
            size_t comma = vol_str.find(',', pos);
            std::string vol = vol_str.substr(pos, comma == std::string::npos ? std::string::npos : comma - pos);
            if (vol == "None" || vol == "unknown" || vol.empty()) {
              id(speaker_unavailable)[idx] = true;
              ESP_LOGI("exclude", "Speaker %d unavailable (vol=%s)", idx, vol.c_str());
            }
            idx++;
            if (comma == std::string::npos) break;
            pos = comma + 1;
          }
    parameters: {}
  - id: highlight_active_player
    mode: restart
    then: 
      - script.execute: 
          id: parse_unavailable_speakers
      - lambda: !lambda |-
          std::string active = id(media_player_entity).state;
          lv_obj_t *cards[] = {
            id(speaker_card_0), id(speaker_card_1), id(speaker_card_2), id(speaker_card_3),
            id(speaker_card_4), id(speaker_card_5), id(speaker_card_6), id(speaker_card_7),
            id(speaker_card_8), id(speaker_card_9), id(speaker_card_10), id(speaker_card_11),
            id(speaker_card_12), id(speaker_card_13), id(speaker_card_14), id(speaker_card_15)
          };
          int excl_count = id(excluded_player_count);
          for (int i = 0; i < id(speaker_count); i++) {
            // Hide excluded players regardless of grouping state
            bool excluded = false;
            for (int e = 0; e < excl_count; e++) {
              if (id(speaker_entity_ids)[i] == id(excluded_player_ids)[e]) {
                excluded = true;
                break;
              }
            }
            if (excluded) {
              lv_obj_add_flag(cards[i], LV_OBJ_FLAG_HIDDEN);
              continue;
            }
            // Hide unavailable speakers
            if (id(speaker_unavailable)[i]) {
              lv_obj_add_flag(cards[i], LV_OBJ_FLAG_HIDDEN);
              continue;
            }
            // Only highlight active player — don't touch grouped card styling
            // update_grouping_panel already set card colors for group state
            if (!lv_obj_has_flag(cards[i], LV_OBJ_FLAG_HIDDEN) &&
                id(speaker_entity_ids)[i] == active) {
              lv_obj_set_style_border_color(cards[i], lv_color_white(), 0);
              lv_obj_set_style_border_width(cards[i], 3, 0);
              lv_obj_set_style_border_opa(cards[i], LV_OPA_COVER, 0);
            }
          }
    parameters: {}
